        }
    POLICY
}
- resource "aws_emr_security_configuration" "example2" {
    configuration = <<EOF
        {
        ... json-data
        }
    EOF
}

The output of this class needs to be very explicit, hence the following structure of the dict:
{
    "failed_checks": [
        {
            "file": "path/to/file",
            "findings: [
                {
                    "resource": "aws_s3_bucket.this",
                    "check_ids": [
                        "CKV_AWS_1",
                        "CKV_AWS_2",
