    "cve": {
        "CVE-2023-123": {
            "suppress_comment": "bla bla",
            "line_number": 1,
        }
    },
    "package": {
        "django": {
            "CVE-2023-456": {
                "suppress_comment": "bla bla",
                "line_number": 1,
            }
        }
        "flask": {
            "suppress_comment": "bla bla",
            "line_number": 1,
        }
    }
}

